// Script: generar_37_fix_modales_safe_area.js
// Que hace: corrige que el contenido de varios modales (incluyendo el
// boton "Eliminar" en el menu de acciones, y los botones de guardar en
// los formularios de vacuna/antiparasitario/medicamento/peso) quedara
// tapado o cortado por la barra de navegacion del sistema operativo del
// celular.
//
// Causa raiz: los modales solo tenian un padding inferior fijo y chico
// (ej. 20px), que no es suficiente en celulares donde la barra de
// navegacion (los botones de inicio/atras del sistema) ocupa espacio
// extra abajo de la pantalla.
//
// Fix: se agrego "env(safe-area-inset-bottom)" -- el estandar para que
// el navegador le diga a la pagina cuanto espacio reservar para esa zona
// segura -- combinado con un padding minimo, en TODOS los modales
// afectados:
//
//   1) app/prevencion/page.tsx -- el modal de Editar/Eliminar (vacunas,
//      antiparasitarios) y el modal grande de crear/editar.
//   2) app/registro-diario/page.tsx -- el mini-formulario de
//      vacuna/antiparasitario/medicamento aplicado hoy.
//   3) components/PesoTracker.tsx -- el modal de registrar peso.
//
// Como correrlo: node generar_37_fix_modales_safe_area.js
// Confirma "OK" para los 3 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/prevencion/page.tsx', "");
escribir('app/registro-diario/page.tsx', "");
escribir('components/PesoTracker.tsx', "");
